- "Total sales" refers to the sum of quantities ordered for each product;
- "Prices across all store views" indicates that the price may vary depending on the store view;
- "Biggest earner" means the product with the highest total revenue.

sql:
SELECT store_name, currency_code
FROM store_views
WHERE locale = 'en_US';

external_knowledge:
- 'shipped orders' refer to orders with a status of 'shipped';
- 'gold coins from the treasure chests' metaphorically represent the total amount of the orders;
- 'products that have been dispatched and are not empty' refers to products with a positive total amount of shipped orders.

sql:
SELECT SUM(total_amount) AS grand_total
FROM orders
WHERE status = 'shipped' AND total_amount > 0;

SELECT DISTINCT store_view_code
FROM inventory
WHERE quantity > 20;

SELECT MIN(sku) AS smallest_sku
FROM products
WHERE status = 'active';

SELECT COUNT(DISTINCT p.sku) AS total_products_with_custom_options
FROM products p
INNER JOIN product_custom_options pco ON p.sku = pco.sku;

